{
  "mode": "method",
  "tests": [
    {
      "name": "successful_reskin_check",
      "input": {
        "submission_status": "failed",
        "action": "advance"
      },
      "output": "reskin_success",
      "notes": "Validates that the reskin is applied correctly when advancing a failed submission."
    },
    {
      "name": "failed_reskin_check",
      "input": {
        "submission_status": "failed",
        "action": "advance"
      },
      "output": "reskin_failed",
      "notes": "Checks that the advancing page is not reskinned when it should be."
    },
    {
      "name": "no_submission_to_advance",
      "input": {
        "submission_status": "none",
        "action": "advance"
      },
      "output": "no_submission_error",
      "notes": "Tests behavior when there are no submissions to advance."
    },
    {
      "name": "multiple_failed_submissions",
      "input": [
        {
          "submission_status": "failed",
          "action": "advance"
        },
        {
          "submission_status": "failed",
          "action": "advance"
        }
      ],
      "output": "multiple_reskin_success",
      "notes": "Validates that multiple failed submissions can be advanced correctly."
    },
    {
      "name": "invalid_action",
      "input": {
        "submission_status": "failed",
        "action": "invalid"
      },
      "output": "invalid_action_error",
      "notes": "Tests the system's response to an invalid action."
    },
    {
      "name": "reskin_on_successful_submission",
      "input": {
        "submission_status": "successful",
        "action": "advance"
      },
      "output": "reskin_not_applicable",
      "notes": "Checks that advancing a successful submission does not trigger a reskin."
    },
    {
      "name": "edge_case_empty_submission_list",
      "input": [],
      "output": "empty_submission_list_error",
      "notes": "Tests the system's response when the submission list is empty."
    },
    {
      "name": "edge_case_large_submission_list",
      "input": [
        {
          "submission_status": "failed",
          "action": "advance"
        },
        {
          "submission_status": "failed",
          "action": "advance"
        },
        {
          "submission_status": "failed",
          "action": "advance"
        },
        {
          "submission_status": "failed",
          "action": "advance"
        },
        {
          "submission_status": "failed",
          "action": "advance"
        },
        {
          "submission_status": "failed",
          "action": "advance"
        },
        {
          "submission_status": "failed",
          "action": "advance"
        },
        {
          "submission_status": "failed",
          "action": "advance"
        }
      ],
      "output": "large_submission_reskin_success",
      "notes": "Validates system performance and correctness with a large number of failed submissions."
    }
  ],
  "assumptions": "The system must handle both valid and invalid actions gracefully.",
  "notes": "Ensure that the reskin adheres to the design assets provided in the Figma link."
}
